SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-potential", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The electric potential at a point on the axial line of a short electric dipole at distance r from the centre is proportional to:", "explanation": "The potential due to a short electric dipole at a point on its axial line is V = kp cos θ/r², where θ = 0° for the axial line. Thus V = kp/r², which means V is proportional to 1/r². The potential falls off faster for a dipole compared to a point charge.", "correct_answer": "B", "concept_tags": ["electric dipole", "axial potential", "inverse square"], "payload": {"question_id": "cuet-phy-elec-potential-14", "subtopic": "Electric Potential and Potential Energy", "topic_name": "Electric Potential", "bloom_level": "understand", "options": [{"key": "A", "text": "1/r", "is_correct": false}, {"key": "B", "text": "1/r²", "is_correct": true}, {"key": "C", "text": "1/r³", "is_correct": false}, {"key": "D", "text": "1/r⁴", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "1/r dependence is characteristic of the potential due to a point charge, not a dipole.", "misconception": "Confusing point charge potential with dipole potential"}, {"option_key": "C", "hint": "1/r³ dependence is characteristic of the electric field of a dipole, not the potential.", "misconception": "Confusing dipole electric field variation with dipole potential variation"}, {"option_key": "D", "hint": "No standard electrostatic quantity for a dipole varies as 1/r⁴ in the far-field approximation.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-potential", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The electric potential at a point on the equatorial plane of a short electric dipole is:", "explanation": "On the equatorial plane of a dipole, the angle θ = 90°. The potential is V = kp cos θ/r² = kp cos 90°/r² = 0. The contributions from the positive and negative charges exactly cancel at every point on the equatorial plane.", "correct_answer": "C", "concept_tags": ["electric dipole", "equatorial potential", "zero potential"], "payload": {"question_id": "cuet-phy-elec-potential-15", "subtopic": "Electric Potential and Potential Energy", "topic_name": "Electric Potential", "bloom_level": "understand", "options": [{"key": "A", "text": "Positive", "is_correct": false}, {"key": "B", "text": "Negative", "is_correct": false}, {"key": "C", "text": "Zero", "is_correct": true}, {"key": "D", "text": "Depends on the dipole moment", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Both charges are equidistant from any point on the equatorial plane, so the positive and negative potentials cancel exactly.", "misconception": null}, {"option_key": "B", "hint": "The negative charge does not dominate since it is at the same distance as the positive charge from any equatorial point.", "misconception": null}, {"option_key": "D", "hint": "While the individual potentials depend on dipole moment, their sum on the equatorial plane is always zero regardless of the dipole moment magnitude.", "misconception": "Thinking the result depends on dipole moment magnitude"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-potential", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The relation between electric field E and electric potential V is given by E = −dV/dr. If V = 4x² volt (where x is in metres), the electric field at x = 1 m is:", "explanation": "Given V = 4x², the electric field component along x is E = −dV/dx = −d(4x²)/dx = −8x. At x = 1 m, E = −8(1) = −8 V/m. The magnitude is 8 V/m directed in the negative x-direction.", "correct_answer": "D", "concept_tags": ["relation between E and V", "potential gradient", "differentiation"], "payload": {"question_id": "cuet-phy-elec-potential-16", "subtopic": "Electric Potential and Potential Energy", "topic_name": "Electric Potential", "bloom_level": "apply", "options": [{"key": "A", "text": "4 V/m in negative x-direction", "is_correct": false}, {"key": "B", "text": "4 V/m in positive x-direction", "is_correct": false}, {"key": "C", "text": "8 V/m in positive x-direction", "is_correct": false}, {"key": "D", "text": "8 V/m in negative x-direction", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "4 V/m would result from forgetting to apply the power rule correctly during differentiation of 4x².", "misconception": "Incorrect differentiation of polynomial"}, {"option_key": "B", "hint": "The direction is wrong. E = −dV/dx gives a negative sign, indicating the field points in the negative x-direction.", "misconception": null}, {"option_key": "C", "hint": "While the magnitude 8 V/m is correct, the direction should be negative x since E = −dV/dx and dV/dx is positive.", "misconception": "Forgetting the negative sign in E = −dV/dr"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-potential", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "The potential at a point on the surface of a uniformly charged non-conducting solid sphere of radius R and total charge Q is V₀. The potential at a point at distance R/2 from the centre is:", "explanation": "Outside and on surface: V₀ = kQ/R. Inside (r < R): V = kQ(3R² − r²)/(2R³). At r = R/2: V = kQ(3R² − R²/4)/(2R³) = kQ(11R²/4)/(2R³) = 11kQ/(8R) = 11V₀/8. The potential inside a solid sphere is higher than the surface potential.", "correct_answer": "D", "concept_tags": ["solid-sphere-potential", "inside-potential", "non-conductor"], "payload": {"question_id": "cuet-phy-elec-potential-17", "subtopic": "Potential inside a solid sphere", "topic_name": "Electric Potential", "bloom_level": "apply", "options": [{"key": "A", "text": "V₀/2", "is_correct": false}, {"key": "B", "text": "V₀", "is_correct": false}, {"key": "C", "text": "3V₀/2", "is_correct": false}, {"key": "D", "text": "11V₀/8", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "V₀/2 would apply if V ∝ r (linear decrease), but the potential inside a solid sphere follows V = kQ(3R² − r²)/(2R³), not a linear law.", "misconception": "Assuming potential decreases linearly inside a solid sphere"}, {"option_key": "B", "hint": "V = V₀ would mean constant potential inside (as in a shell). For a solid sphere, the potential increases from surface toward the centre.", "misconception": "Confusing solid sphere with hollow shell"}, {"option_key": "C", "hint": "3V₀/2 is the potential at the centre (r = 0): V = kQ × 3R²/(2R³) = 3kQ/(2R) = 3V₀/2. At r = R/2, it''s less than this.", "misconception": "Using the centre value instead of calculating at r = R/2"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-potential", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "Two concentric metallic shells of radii R and 2R carry charges Q and −2Q respectively. The potential at distance r = 3R from the centre is:", "explanation": "For r > 2R (outside both shells), both shells act as point charges at the centre. V = k(Q + (−2Q))/(3R) = k(−Q)/(3R) = −kQ/(3R). The potential depends on the total enclosed charge.", "correct_answer": "B", "concept_tags": ["concentric-shells", "superposition", "external-potential"], "payload": {"question_id": "cuet-phy-elec-potential-18", "subtopic": "Potential of concentric shells", "topic_name": "Electric Potential", "bloom_level": "apply", "options": [{"key": "A", "text": "kQ/(3R)", "is_correct": false}, {"key": "B", "text": "−kQ/(3R)", "is_correct": true}, {"key": "C", "text": "−3kQ/(2R)", "is_correct": false}, {"key": "D", "text": "Zero", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This ignores the −2Q on the outer shell. The net charge is Q + (−2Q) = −Q, not +Q.", "misconception": "Considering only the inner shell''s charge"}, {"option_key": "C", "hint": "−3kQ/(2R) might come from incorrectly adding potentials. At r = 3R: V = kQ/(3R) + k(−2Q)/(3R) = −kQ/(3R).", "misconception": "Using different distances for the two shells at an external point"}, {"option_key": "D", "hint": "Zero potential would require Q_net = 0, but Q + (−2Q) = −Q ≠ 0.", "misconception": "Thinking opposite charges on concentric shells cancel the potential"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-potential", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A charge Q is distributed uniformly on a ring of radius R. A point charge −q is moved from infinity to the centre of the ring. The work done by the external agent is:", "explanation": "V at centre of ring = kQ/R (all charge elements on the ring are at distance R from the centre). Work done by external agent = Change in PE = (−q)(V_centre − V_∞) = (−q)(kQ/R − 0) = −kQq/R. The negative sign means the external agent does negative work (the field does positive work pulling −q toward the positive ring).", "correct_answer": "C", "concept_tags": ["ring-potential", "work-by-external-agent", "centre-potential"], "payload": {"question_id": "cuet-phy-elec-potential-19", "subtopic": "Work and potential energy", "topic_name": "Electric Potential", "bloom_level": "apply", "options": [{"key": "A", "text": "kQq/R", "is_correct": false}, {"key": "B", "text": "kQq/R²", "is_correct": false}, {"key": "C", "text": "−kQq/R", "is_correct": true}, {"key": "D", "text": "Zero", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Positive work would mean the agent pushes against the field. But −q is attracted to the positive ring, so the field does the work and the agent does negative work.", "misconception": "Getting the sign wrong — confusing work by field with work against field"}, {"option_key": "B", "hint": "kQq/R² has dimensions of force, not energy. Work = charge × potential, not charge × field.", "misconception": "Confusing potential (kQ/R) with field (kQ/R²)"}, {"option_key": "D", "hint": "Zero work implies no change in PE, but moving from infinity (V = 0) to the centre (V = kQ/R) definitely changes PE.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-potential", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "Eight identical point charges q are placed at the eight corners of a cube of side a. The electrostatic potential energy of the system is (k = 1/4πε₀):", "explanation": "A cube has 8 vertices. Total pairs = C(8,2) = 28. There are three types of pairs by distance: 12 edge pairs (distance a), 12 face-diagonal pairs (distance a√2), and 4 body-diagonal pairs (distance a√3). Total PE = kq²[12/a + 12/(a√2) + 4/(a√3)] = (kq²/a)[12 + 12/√2 + 4/√3] = (kq²/a)[12 + 6√2 + 4√3/3].", "correct_answer": "D", "concept_tags": ["potential energy of system", "cube arrangement", "multiple charge pairs"], "payload": {"question_id": "cuet-phy-elec-potential-20", "subtopic": "Electric Potential and Potential Energy", "topic_name": "Electric Potential", "bloom_level": "analyze", "options": [{"key": "A", "text": "(kq²/a)(12 + 6√2)", "is_correct": false}, {"key": "B", "text": "(kq²/a)(24 + 12√2 + 4√3)", "is_correct": false}, {"key": "C", "text": "(kq²/a)(12 + 12√2 + 4√3)", "is_correct": false}, {"key": "D", "text": "(kq²/a)(12 + 6√2 + 4√3/3)", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "This expression omits the 4 body-diagonal pairs entirely. A cube has edge, face-diagonal, and body-diagonal pairs — all must be included.", "misconception": "Forgetting body-diagonal pairs in a cube"}, {"option_key": "B", "hint": "The coefficients 24 and 12 are twice the actual number of edge and face-diagonal pairs. There are 12 edges and 12 face diagonals, not 24 and 12.", "misconception": "Double-counting pairs"}, {"option_key": "C", "hint": "The face-diagonal contribution should be 12/(a√2) = 6√2·(kq²/a), not 12√2. Also 4/√3 = 4√3/3, not 4√3.", "misconception": "Error in rationalizing denominators"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-potential", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "easy", "question_text": "The diagram shows equipotential surfaces at V₁ = 40 V, V₂ = 30 V, V₃ = 20 V, and V₄ = 10 V drawn as parallel vertical lines from left to right. The electric field points:", "explanation": "The electric field always points from higher potential to lower potential, perpendicular to the equipotential surfaces. Since V decreases from left to right (40 → 10 V), E points from left to right. The equal spacing of equipotential surfaces indicates a uniform field.", "correct_answer": "A", "concept_tags": ["equipotential-surfaces", "electric-field-direction", "uniform-field"], "payload": {"question_id": "cuet-phy-elec-potential-21", "subtopic": "Relation between E and V", "topic_name": "Electric Potential", "bloom_level": "understand", "options": [{"key": "A", "text": "From left to right (from higher to lower potential)", "is_correct": true}, {"key": "B", "text": "From right to left (from lower to higher potential)", "is_correct": false}, {"key": "C", "text": "Upward, parallel to the equipotential surfaces", "is_correct": false}, {"key": "D", "text": "The direction cannot be determined from the diagram", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The electric field points in the direction of decreasing potential, not increasing. E = −dV/dr means E goes from high V to low V.", "misconception": "Reversing the relationship between E and V"}, {"option_key": "C", "hint": "The electric field is always perpendicular to equipotential surfaces, never parallel. No work is done along an equipotential.", "misconception": "Confusing field direction with equipotential direction"}, {"option_key": "D", "hint": "The direction is fully determined: E is perpendicular to the equipotential surfaces and points from high to low potential.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-potential", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "medium", "question_text": "The diagram shows concentric circular equipotential surfaces around a positive point charge. The radii are R, 2R, and 3R with potentials V₁, V₂, and V₃ respectively. Which relation is correct?", "explanation": "For a point charge, V = kQ/r. So V₁ = kQ/R, V₂ = kQ/(2R), V₃ = kQ/(3R). Therefore V₁ > V₂ > V₃, and V₁ = 2V₂ = 3V₃. Also, V₁ − V₂ = kQ/R − kQ/(2R) = kQ/(2R), and V₂ − V₃ = kQ/(2R) − kQ/(3R) = kQ/(6R). So the spacing is not equal — the potential drops more rapidly closer to the charge.", "correct_answer": "C", "concept_tags": ["point-charge-potential", "equipotential-spacing", "inverse-distance"], "payload": {"question_id": "cuet-phy-elec-potential-22", "subtopic": "Potential due to point charge", "topic_name": "Electric Potential", "bloom_level": "analyze", "options": [{"key": "A", "text": "V₁ = V₂ = V₃ (equal everywhere)", "is_correct": false}, {"key": "B", "text": "V₁ < V₂ < V₃ (increases outward)", "is_correct": false}, {"key": "C", "text": "V₁ > V₂ > V₃ and V₁ − V₂ > V₂ − V₃", "is_correct": true}, {"key": "D", "text": "V₁ > V₂ > V₃ and V₁ − V₂ = V₂ − V₃", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The potential of a point charge varies with distance (V = kQ/r). It cannot be equal at different distances.", "misconception": "Confusing equipotential surfaces with constant potential everywhere"}, {"option_key": "B", "hint": "For a positive charge, V = kQ/r decreases with distance, not increases.", "misconception": "Reversing the relationship between V and r"}, {"option_key": "D", "hint": "V₁ − V₂ = kQ/(2R) while V₂ − V₃ = kQ/(6R). These are unequal. Equipotential spacing is non-uniform for a point charge.", "misconception": "Assuming uniform spacing of equipotential surfaces"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-potential", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "medium", "question_text": "The graph shows the variation of electric potential V with distance r along the axis of a short electric dipole. Which curve correctly represents this variation for r >> a?", "explanation": "On the axial line of a dipole at large distance r, V = kp cosθ/r². On the axis, θ = 0°, so V = kp/r². The potential falls off as 1/r² — faster than a point charge (1/r) but slower than the field (1/r³). Curve B correctly shows this 1/r² dependence.", "correct_answer": "B", "concept_tags": ["dipole-potential", "axial-line", "inverse-square-potential"], "payload": {"question_id": "cuet-phy-elec-potential-23", "subtopic": "Potential due to a dipole", "topic_name": "Electric Potential", "bloom_level": "analyze", "options": [{"key": "A", "text": "Curve A: V ∝ 1/r", "is_correct": false}, {"key": "B", "text": "Curve B: V ∝ 1/r²", "is_correct": true}, {"key": "C", "text": "Curve C: V = constant", "is_correct": false}, {"key": "D", "text": "Curve D: V ∝ r", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "V ∝ 1/r is the potential of a point charge (monopole). A dipole''s potential falls faster because the contributions of +q and −q partially cancel.", "misconception": "Using point charge potential for a dipole"}, {"option_key": "C", "hint": "A constant potential describes an equipotential surface, not the variation along the axis.", "misconception": "Confusing potential along axis with an equipotential surface"}, {"option_key": "D", "hint": "V increasing linearly with r is unphysical for a localized charge distribution. V must decrease at large r.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-potential", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "hard", "question_text": "The figure shows the variation of electric potential V along the x-axis. The graph shows V constant from x = 0 to x = a, then linearly decreasing from x = a to x = 2a, then constant again for x > 2a. The electric field in the region a < x < 2a is:", "explanation": "E = −dV/dx. In region a < x < 2a, V decreases linearly from V₀ to 0 over distance a. So dV/dx = (0 − V₀)/a = −V₀/a. Therefore E = −(−V₀/a) = V₀/a, directed in the +x direction. In regions where V is constant (0 < x < a and x > 2a), E = 0.", "correct_answer": "D", "concept_tags": ["E-from-V-graph", "potential-gradient", "field-calculation"], "payload": {"question_id": "cuet-phy-elec-potential-24", "subtopic": "Relation between E and V", "topic_name": "Electric Potential", "bloom_level": "analyze", "options": [{"key": "A", "text": "Zero", "is_correct": false}, {"key": "B", "text": "V₀/a, in the −x direction", "is_correct": false}, {"key": "C", "text": "V₀/(2a), in the +x direction", "is_correct": false}, {"key": "D", "text": "V₀/a, in the +x direction", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "E = 0 only where V is constant (flat graph). In the linearly decreasing region, the slope is non-zero, so E is non-zero.", "misconception": "Applying E = 0 to a region with changing potential"}, {"option_key": "B", "hint": "The magnitude V₀/a is correct, but the direction is wrong. Since V decreases in the +x direction, E = −dV/dx is positive (+x direction).", "misconception": "Getting the sign wrong in E = −dV/dx"}, {"option_key": "C", "hint": "V₀/(2a) uses 2a as the distance, but the potential drops from V₀ to 0 over distance a (from x = a to x = 2a), not 2a.", "misconception": "Using the wrong distance interval"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-potential", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): No work is done in moving a charge along an equipotential surface.\nReason (R): The electric field is always perpendicular to the equipotential surface.", "explanation": "Both A and R are true, and R correctly explains A. Since E ⊥ equipotential surface, the component of E along the surface is zero. Therefore, force on charge along the surface is zero, and work W = F·d = 0. The perpendicularity is what ensures zero work.", "correct_answer": "A", "concept_tags": ["equipotential", "zero-work", "perpendicular-field"], "payload": {"question_id": "cuet-phy-elec-potential-25", "subtopic": "Equipotential surfaces", "topic_name": "Electric Potential", "bloom_level": "understand", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "R directly explains A: because E is perpendicular to the surface, the force component along the surface is zero, hence zero work.", "misconception": "Not connecting the perpendicularity with zero work"}, {"option_key": "C", "hint": "R is correct — E is always perpendicular to equipotential surfaces. This is a fundamental property derived from E = −∇V.", "misconception": null}, {"option_key": "D", "hint": "A is correct — since potential is constant on an equipotential surface, ΔV = 0, so W = qΔV = 0.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-potential", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): The electric field is always perpendicular to the equipotential surface at every point.\nReason (R): No work is done in moving a charge along an equipotential surface.", "explanation": "Both the assertion and the reason are correct. If the electric field had a component along the equipotential surface, work would be done in moving a charge along the surface, contradicting the definition of an equipotential surface. Hence R correctly explains A — the perpendicularity ensures zero work along the surface.", "correct_answer": "A", "concept_tags": ["equipotential surface", "electric field direction", "work done"], "payload": {"question_id": "cuet-phy-elec-potential-26", "subtopic": "Electric Potential and Potential Energy", "topic_name": "Electric Potential", "bloom_level": "understand", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "R directly explains why E must be perpendicular — if E had a tangential component, work would be done along the surface, violating the equipotential condition.", "misconception": "Not recognizing the causal link between zero work and perpendicularity"}, {"option_key": "C", "hint": "R is indeed correct; by definition, no work is done in moving a charge on an equipotential surface since ΔV = 0.", "misconception": null}, {"option_key": "D", "hint": "A is a well-established fact in electrostatics — the electric field lines are always normal to equipotential surfaces.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-potential", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "hard", "question_text": "Assertion (A): The potential at the centre of a uniformly charged non-conducting solid sphere is 1.5 times the potential at its surface.\nReason (R): The electric field inside a uniformly charged solid sphere is proportional to the distance from the centre.", "explanation": "Both A and R are true, and R is the correct explanation of A. V_centre = 3kQ/(2R) = 1.5 × kQ/R = 1.5 V_surface (A is true). R is true: E_inside = ρr/(3ε₀) ∝ r. R explains A because integrating this linear field from surface to centre gives the extra potential: V_centre − V_surface = ∫₀ᴿ E dr = kQ/(2R), leading to V_centre = 3kQ/(2R).", "correct_answer": "A", "concept_tags": ["solid-sphere", "centre-potential", "linear-field"], "payload": {"question_id": "cuet-phy-elec-potential-27", "subtopic": "Potential inside solid sphere", "topic_name": "Electric Potential", "bloom_level": "analyze", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "R explains A directly — the 1.5 factor arises from integrating E ∝ r from the surface inward. The linear field profile is the reason for the specific ratio.", "misconception": "Not recognizing that the field profile determines the potential profile"}, {"option_key": "C", "hint": "R is correct — inside a uniformly charged solid sphere, E = ρr/(3ε₀), which is indeed proportional to r.", "misconception": null}, {"option_key": "D", "hint": "A is correct — V_centre = kQ(3R²)/(2R³) = 3kQ/(2R) = 1.5 × kQ/R = 1.5 V_surface.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-potential", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "hard", "question_text": "Assertion (A): The electrostatic potential energy of two like charges is positive.\nReason (R): Electric potential is always positive in the region surrounding a positive charge.", "explanation": "The assertion is correct: for two like charges (both positive or both negative), U = kq₁q₂/r is positive since the product q₁q₂ is positive. The reason is also correct: the potential around a positive charge is indeed positive (V = kq/r > 0 when q > 0). However, R does not explain A because A applies to both like positive and like negative charges, and the positivity of PE comes from the product of charges, not from the potential of a single charge.", "correct_answer": "B", "concept_tags": ["potential energy sign", "like charges", "electric potential sign"], "payload": {"question_id": "cuet-phy-elec-potential-28", "subtopic": "Electric Potential and Potential Energy", "topic_name": "Electric Potential", "bloom_level": "evaluate", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": false}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": true}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "While both statements are independently true, R does not explain A. Two negative charges also have positive PE, but R talks about potential near positive charges only.", "misconception": "Assuming any two correct statements must be causally related"}, {"option_key": "C", "hint": "R is a correct statement — the potential around a positive point charge is indeed positive at all points.", "misconception": null}, {"option_key": "D", "hint": "A is correct — like charges (++ or −−) always give a positive product q₁q₂, making U = kq₁q₂/r positive.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-potential", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "medium", "question_text": "Match the following physical situations (Column I) with the corresponding electric potential (Column II):\n\nColumn I:\nA. Inside a uniformly charged spherical shell\nB. At the surface of a uniformly charged spherical shell of radius R\nC. At a distance 2R from the centre of a uniformly charged spherical shell\nD. At infinity\n\nColumn II:\n1. Zero\n2. kQ/R\n3. kQ/2R\n4. kQ/R (same as at surface)", "explanation": "Inside the shell (A), the potential is constant and equal to the surface potential: kQ/R, so A→4. At the surface (B), V = kQ/R, so B→2. At distance 2R (C), V = kQ/2R, so C→3. At infinity (D), V = 0, so D→1.", "correct_answer": "C", "concept_tags": ["spherical shell potential", "potential variation", "matching"], "payload": {"question_id": "cuet-phy-elec-potential-29", "subtopic": "Electric Potential and Potential Energy", "topic_name": "Electric Potential", "bloom_level": "understand", "options": [{"key": "A", "text": "A-1, B-2, C-3, D-4", "is_correct": false}, {"key": "B", "text": "A-2, B-4, C-3, D-1", "is_correct": false}, {"key": "C", "text": "A-4, B-2, C-3, D-1", "is_correct": true}, {"key": "D", "text": "A-3, B-2, C-4, D-1", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "A-1 implies zero potential inside the shell, which is incorrect. The potential inside is constant and equal to the surface potential kQ/R.", "misconception": "Confusing zero electric field inside shell with zero potential"}, {"option_key": "B", "hint": "A-2 and B-4 both give kQ/R but the match labels are swapped incorrectly in the list structure.", "misconception": null}, {"option_key": "D", "hint": "A-3 would give kQ/2R inside the shell, which is wrong. The potential inside is kQ/R, not kQ/2R.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-potential", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "hard", "question_text": "Match the following quantities (Column I) with their distance dependence from a point charge (Column II):\n\nColumn I:\nA. Electric field due to point charge\nB. Electric potential due to point charge\nC. Electric field due to dipole (far field)\nD. Electric potential due to dipole (far field)\n\nColumn II:\n1. ∝ 1/r\n2. ∝ 1/r²\n3. ∝ 1/r³\n4. ∝ 1/r⁴", "explanation": "Electric field due to a point charge E = kq/r², so A→2. Electric potential due to a point charge V = kq/r, so B→1. Electric field due to a dipole varies as 1/r³, so C→3. Electric potential due to a dipole varies as 1/r², so D→2. Hence the correct matching is A-2, B-1, C-3, D-2.", "correct_answer": "B", "concept_tags": ["distance dependence", "point charge", "dipole", "field and potential"], "payload": {"question_id": "cuet-phy-elec-potential-30", "subtopic": "Electric Potential and Potential Energy", "topic_name": "Electric Potential", "bloom_level": "analyze", "options": [{"key": "A", "text": "A-1, B-2, C-3, D-4", "is_correct": false}, {"key": "B", "text": "A-2, B-1, C-3, D-2", "is_correct": true}, {"key": "C", "text": "A-2, B-1, C-4, D-3", "is_correct": false}, {"key": "D", "text": "A-1, B-2, C-4, D-3", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "A-1 would mean E ∝ 1/r for a point charge, but the correct dependence is E ∝ 1/r² (Coulomb''s law).", "misconception": "Confusing potential and field dependence for point charge"}, {"option_key": "C", "hint": "C-4 would mean dipole field varies as 1/r⁴, which is incorrect. Dipole field varies as 1/r³.", "misconception": null}, {"option_key": "D", "hint": "A-1 and B-2 are swapped — field goes as 1/r² and potential goes as 1/r for a point charge.", "misconception": "Mixing up field and potential dependencies"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-potential", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "Electric potential is a scalar quantity.", "explanation": "TRUE. Electric potential V = W/q (work per unit charge) is a scalar. Unlike the electric field (which is a vector), potential has no direction — it has only magnitude (positive, negative, or zero). The scalar nature makes superposition of potentials simpler than superposition of fields.", "correct_answer": "A", "concept_tags": ["potential-scalar", "scalar-quantity"], "payload": {"question_id": "cuet-phy-elec-potential-31", "subtopic": "Nature of electric potential", "topic_name": "Electric Potential", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Potential is defined as work/charge (W/q), both of which are scalars. A scalar divided by a scalar is a scalar, not a vector.", "misconception": "Confusing electric potential (scalar) with electric field (vector)"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-potential", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "The electric potential decreases along the direction of the electric field.", "explanation": "TRUE. E = −dV/dr implies that V decreases in the direction of E. The electric field points from higher potential to lower potential. This is analogous to a ball rolling downhill — the gravitational field points in the direction of decreasing gravitational potential.", "correct_answer": "A", "concept_tags": ["potential-decrease", "field-direction", "gradient"], "payload": {"question_id": "cuet-phy-elec-potential-32", "subtopic": "E-V relationship", "topic_name": "Electric Potential", "bloom_level": "understand", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "From E = −dV/dr, if E > 0 in some direction, then dV/dr < 0 in that direction, meaning V decreases. The statement is true.", "misconception": "Forgetting the negative sign in E = −dV/dr"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-potential", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "The electric potential at the equatorial point of a dipole (on the perpendicular bisector of the dipole) is maximum.", "explanation": "FALSE. The potential at the equatorial point of a dipole is zero, not maximum. At any point on the perpendicular bisector, the distances from both charges are equal, so V = kq/r + k(−q)/r = 0. The maximum potential occurs on the axial line near the positive charge.", "correct_answer": "B", "concept_tags": ["dipole-potential", "equatorial-point", "zero-potential"], "payload": {"question_id": "cuet-phy-elec-potential-33", "subtopic": "Potential due to a dipole", "topic_name": "Electric Potential", "bloom_level": "understand", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The potential at the equatorial point is exactly zero because equal and opposite charges contribute equally. V = k(+q)/r + k(−q)/r = 0.", "misconception": "Confusing the equatorial point''s zero potential with maximum potential"}]}}]'::jsonb, 'deploy-2026-03-05-b09');

SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-potential", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "Two equipotential surfaces can intersect each other.", "explanation": "This statement is FALSE. If two equipotential surfaces intersected, the point of intersection would have two different values of potential simultaneously, which is physically impossible since potential is a single-valued function of position.", "correct_answer": "B", "concept_tags": ["equipotential surface", "properties", "intersection"], "payload": {"question_id": "cuet-phy-elec-potential-34", "subtopic": "Electric Potential and Potential Energy", "topic_name": "Electric Potential", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "If two equipotential surfaces intersected, the point of intersection would have two different potential values, which violates the definition of a scalar field.", "misconception": "Thinking equipotential surfaces can cross like field lines in some cases"}, {"option_key": "C", "hint": "This option is not applicable for true/false questions.", "misconception": null}, {"option_key": "D", "hint": "This option is not applicable for true/false questions.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-potential", "exam_ids": ["CUET", "NEET"], "question_type": "fill-in-blanks", "difficulty": "medium", "question_text": "The potential at the centre of a uniformly charged ring of total charge Q and radius R is _____.", "explanation": "Every point on the ring is at distance R from the centre (by the definition of a ring). Since potential is a scalar, V = kQ/R (no vector cancellation). This is the same as the potential at distance R from a point charge Q, because all charge elements are equidistant from the centre.", "correct_answer": "B", "concept_tags": ["ring-potential", "centre", "scalar-addition"], "payload": {"question_id": "cuet-phy-elec-potential-35", "subtopic": "Potential due to continuous distribution", "topic_name": "Electric Potential", "bloom_level": "apply", "options": [{"key": "A", "text": "Zero", "is_correct": false}, {"key": "B", "text": "kQ/R", "is_correct": true}, {"key": "C", "text": "kQ/R²", "is_correct": false}, {"key": "D", "text": "2kQ/R", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The electric field at the centre of a ring is zero (by symmetry), but the potential is not. Don''t confuse E = 0 with V = 0.", "misconception": "Thinking zero field at centre means zero potential"}, {"option_key": "C", "hint": "kQ/R² has dimensions of electric field, not potential. Potential = kQ/R.", "misconception": "Confusing field and potential formulas"}, {"option_key": "D", "hint": "There is no factor of 2. Each charge element dq at distance R contributes k·dq/R, and summing gives kQ/R.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-potential", "exam_ids": ["CUET", "NEET"], "question_type": "fill-in-blanks", "difficulty": "medium", "question_text": "A charge of 10 μC is placed at the origin. The potential at a point 0.3 m from the charge is _____ V. (Take k = 9 × 10⁹ N m² C⁻²)", "explanation": "Using V = kq/r = 9 × 10⁹ × 10 × 10⁻⁶ / 0.3 = 9 × 10⁹ × 10⁻⁵ / 0.3 = 9 × 10⁴ / 0.3 = 3 × 10⁵ V. The potential is 3 × 10⁵ V or 300000 V.", "correct_answer": "D", "concept_tags": ["electric potential calculation", "point charge", "numerical"], "payload": {"question_id": "cuet-phy-elec-potential-36", "subtopic": "Electric Potential and Potential Energy", "topic_name": "Electric Potential", "bloom_level": "apply", "options": [{"key": "A", "text": "3 × 10⁴", "is_correct": false}, {"key": "B", "text": "9 × 10⁵", "is_correct": false}, {"key": "C", "text": "3 × 10⁶", "is_correct": false}, {"key": "D", "text": "3 × 10⁵", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "3 × 10⁴ is ten times too small. Check the power of ten in the calculation: 9 × 10⁹ × 10⁻⁵ = 9 × 10⁴, and dividing by 0.3 gives 3 × 10⁵.", "misconception": "Error in handling powers of ten"}, {"option_key": "B", "hint": "9 × 10⁵ would result from not dividing by 0.3 or using an incorrect distance.", "misconception": null}, {"option_key": "C", "hint": "3 × 10⁶ is ten times too large, likely from using the charge as 100 μC instead of 10 μC.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-potential", "exam_ids": ["CUET", "NEET"], "question_type": "scenario-based", "difficulty": "medium", "question_text": "In a laboratory experiment, a student places a +5 μC charge at point A and a +10 μC charge at point B, separated by a distance of 1 m. She wants to find a point on the line joining A and B where the electric potential is zero. She assumes both charges are in free space.\n\nThe student''s observation should be that:", "explanation": "Since both charges are positive, the potential V = kq₁/r₁ + kq₂/r₂ is always positive at every point on the line joining them (and everywhere in space, since both terms are positive). There is no point where the net potential is zero. For potential to be zero between two charges, the charges must be of opposite sign.", "correct_answer": "C", "concept_tags": ["superposition of potential", "like charges", "zero potential"], "payload": {"question_id": "cuet-phy-elec-potential-37", "subtopic": "Electric Potential and Potential Energy", "topic_name": "Electric Potential", "bloom_level": "apply", "options": [{"key": "A", "text": "The zero potential point lies between A and B at 1/3 m from A", "is_correct": false}, {"key": "B", "text": "The zero potential point lies between A and B at the midpoint", "is_correct": false}, {"key": "C", "text": "No point on the line joining A and B has zero potential", "is_correct": true}, {"key": "D", "text": "The zero potential point lies outside AB at 1 m from B", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This would be the null point for electric field (not potential) between charges of different magnitudes, and even then only for opposite charges would potential be zero between them.", "misconception": "Confusing zero field point with zero potential point"}, {"option_key": "B", "hint": "At the midpoint, both positive charges contribute positive potentials, so the net potential is positive, not zero.", "misconception": "Assuming symmetry implies zero potential"}, {"option_key": "D", "hint": "Even outside the charges, both positive charges contribute positive potentials at all points, so the potential cannot be zero anywhere.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-potential", "exam_ids": ["CUET", "NEET"], "question_type": "scenario-based", "difficulty": "hard", "question_text": "An electron (charge = −1.6 × 10⁻¹⁹ C, mass = 9.1 × 10⁻³¹ kg) is accelerated from rest through a potential difference of 100 V. Calculate its final kinetic energy and speed.", "explanation": "KE = |q|ΔV = 1.6 × 10⁻¹⁹ × 100 = 1.6 × 10⁻¹⁷ J = 100 eV. Speed: ½mv² = KE, so v = √(2KE/m) = √(2 × 1.6 × 10⁻¹⁷ / 9.1 × 10⁻³¹) = √(3.516 × 10¹³) = 5.93 × 10⁶ m/s.", "correct_answer": "D", "concept_tags": ["electron-acceleration", "kinetic-energy", "potential-difference"], "payload": {"question_id": "cuet-phy-elec-potential-38", "subtopic": "Motion in electric potential", "topic_name": "Electric Potential", "bloom_level": "apply", "options": [{"key": "A", "text": "KE = 1.6 × 10⁻¹⁷ J; v = 5.93 × 10⁵ m/s", "is_correct": false}, {"key": "B", "text": "KE = 1.6 × 10⁻¹⁹ J; v = 5.93 × 10⁶ m/s", "is_correct": false}, {"key": "C", "text": "KE = 1.6 × 10⁻¹⁷ J; v = 5.93 × 10⁷ m/s", "is_correct": false}, {"key": "D", "text": "KE = 1.6 × 10⁻¹⁷ J; v = 5.93 × 10⁶ m/s", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "The KE is correct but the speed is off by a factor of 10. Check: v = √(2 × 1.6 × 10⁻¹⁷/9.1 × 10⁻³¹) ≈ 5.93 × 10⁶, not 10⁵.", "misconception": "Error in square root calculation"}, {"option_key": "B", "hint": "KE = qV = 1.6 × 10⁻¹⁹ × 100 = 1.6 × 10⁻¹⁷ J, not 10⁻¹⁹ J. You forgot to multiply by the potential difference.", "misconception": "Using the charge value directly as KE without multiplying by V"}, {"option_key": "C", "hint": "v = 5.93 × 10⁷ m/s is about 20% of the speed of light, which is too high for 100V acceleration. Check the exponent in the square root.", "misconception": "Error in exponent during square root calculation"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-potential", "exam_ids": ["CUET", "NEET"], "question_type": "logical-sequence", "difficulty": "medium", "question_text": "Arrange the following in order of increasing electric potential (lowest first) for a positive point charge Q placed at the origin:\n\n1. A point at distance 4R from Q\n2. A point at distance R from Q\n3. A point at distance 2R from Q\n4. A point at infinity", "explanation": "V = kQ/r for positive Q. V(∞) = 0 (lowest). V(4R) = kQ/(4R). V(2R) = kQ/(2R). V(R) = kQ/R (highest). Increasing order: 0 < kQ/(4R) < kQ/(2R) < kQ/R. So: 4 (infinity) → 1 (4R) → 3 (2R) → 2 (R).", "correct_answer": "B", "concept_tags": ["potential-ordering", "distance-dependence", "positive-charge"], "payload": {"question_id": "cuet-phy-elec-potential-39", "subtopic": "Potential variation with distance", "topic_name": "Electric Potential", "bloom_level": "apply", "options": [{"key": "A", "text": "2 → 3 → 1 → 4", "is_correct": false}, {"key": "B", "text": "4 → 1 → 3 → 2", "is_correct": true}, {"key": "C", "text": "4 → 3 → 1 → 2", "is_correct": false}, {"key": "D", "text": "1 → 3 → 2 → 4", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This gives decreasing order (highest to lowest), not increasing. Point 2 (distance R) has the highest potential.", "misconception": "Reversing the required order"}, {"option_key": "C", "hint": "This swaps items 1 (4R) and 3 (2R). Since V ∝ 1/r, the closer point (2R) has higher potential than the farther point (4R).", "misconception": "Confusing which distance gives higher potential"}, {"option_key": "D", "hint": "This starts with 4R and ends with infinity (V = 0), but infinity has the lowest potential for a positive charge, so it should come first.", "misconception": "Forgetting that V = 0 at infinity is the minimum for positive charge"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-potential", "exam_ids": ["CUET", "NEET"], "question_type": "logical-sequence", "difficulty": "hard", "question_text": "Arrange the following charge configurations in order of increasing electric potential at a point P located at distance d from each configuration (from lowest to highest potential):", "explanation": "V = kq/d, which is directly proportional to the charge q. For negative charges, V is negative; for positive charges, V is positive. In ascending order: −2kQ/d < −kQ/d < +kQ/d < +2kQ/d, i.e., −2Q → −Q → +Q → +2Q.", "correct_answer": "A", "concept_tags": ["potential-comparison", "charge-sign", "ordering"], "payload": {"question_id": "cuet-phy-elec-potential-40", "subtopic": "Potential due to point charges", "topic_name": "Electric Potential", "bloom_level": "apply", "options": [{"key": "A", "text": "−2Q → −Q → +Q → +2Q (i.e., 1 → 2 → 3 → 4)", "is_correct": true}, {"key": "B", "text": "+2Q → +Q → −Q → −2Q (i.e., 4 → 3 → 2 → 1)", "is_correct": false}, {"key": "C", "text": "−Q → −2Q → +Q → +2Q (i.e., 2 → 1 → 3 → 4)", "is_correct": false}, {"key": "D", "text": "+Q → +2Q → −Q → −2Q (i.e., 3 → 4 → 2 → 1)", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "This is decreasing order (highest to lowest). The question asks for increasing order.", "misconception": "Reversing the requested order"}, {"option_key": "C", "hint": "−Q gives V = −kQ/d and −2Q gives V = −2kQ/d. Since −2kQ/d < −kQ/d, the −2Q charge gives the lower potential.", "misconception": "Comparing magnitudes instead of signed values"}, {"option_key": "D", "hint": "This places positive potentials before negative ones. Negative values are always less than positive values.", "misconception": "Ignoring the sign of the potential"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The dimension of capacitance is:", "explanation": "C = Q/V. Dimension of Q = [AT], V = [ML²T⁻³A⁻¹]. So C = [AT]/[ML²T⁻³A⁻¹] = [M⁻¹L⁻²T⁴A²]. This can also be verified: 1 farad = 1 C/V = 1 C²/(J) = 1 A²s⁴/(kg·m²).", "correct_answer": "C", "concept_tags": ["capacitance-dimension", "dimensional-analysis"], "payload": {"question_id": "cuet-phy-elec-capacitor-01", "subtopic": "Capacitance basics", "topic_name": "Capacitance and Capacitors", "bloom_level": "remember", "options": [{"key": "A", "text": "[ML²T⁻²A⁻²]", "is_correct": false}, {"key": "B", "text": "[M⁻¹L⁻²T³A²]", "is_correct": false}, {"key": "C", "text": "[M⁻¹L⁻²T⁴A²]", "is_correct": true}, {"key": "D", "text": "[MLT⁻²A⁻¹]", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "[ML²T⁻²A⁻²] is the dimension of inductance (L = V·s/A), not capacitance.", "misconception": "Confusing capacitance with inductance dimensions"}, {"option_key": "B", "hint": "T³ is incorrect — the time exponent should be T⁴ (from T in charge and T⁻³ in voltage denominator).", "misconception": "Arithmetic error in exponent calculation"}, {"option_key": "D", "hint": "[MLT⁻²A⁻¹] is the dimension of magnetic field (B), not capacitance.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "A conducting slab of thickness t is introduced between the plates of a parallel plate capacitor with plate separation d (t < d). The new capacitance is:", "explanation": "A conducting slab has infinite dielectric constant. It effectively reduces the gap to (d − t), as the field inside the conductor is zero. The capacitance becomes C'' = ε₀A/(d − t). Unlike a dielectric, a conductor completely eliminates the field in its interior.", "correct_answer": "B", "concept_tags": ["conducting-slab", "effective-gap", "capacitance-increase"], "payload": {"question_id": "cuet-phy-elec-capacitor-02", "subtopic": "Conducting slab in capacitor", "topic_name": "Capacitance and Capacitors", "bloom_level": "understand", "options": [{"key": "A", "text": "ε₀A/d (unchanged)", "is_correct": false}, {"key": "B", "text": "ε₀A/(d − t)", "is_correct": true}, {"key": "C", "text": "ε₀A/(d + t)", "is_correct": false}, {"key": "D", "text": "ε₀A/t", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The conducting slab eliminates the field in its interior, reducing the effective gap. Capacitance must increase, not remain the same.", "misconception": "Thinking the slab has no effect"}, {"option_key": "C", "hint": "d + t would mean the gap increases, but the slab is placed inside the existing gap, reducing the effective air gap to d − t.", "misconception": "Adding instead of subtracting the slab thickness"}, {"option_key": "D", "hint": "ε₀A/t would apply if the conducting slab filled the entire gap except a vanishingly small space. The effective gap is d − t, not t.", "misconception": "Using slab thickness instead of remaining gap"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The energy stored in a capacitor of capacitance C charged to voltage V is equivalent to the energy stored in the electric field between the plates. The energy per unit volume (energy density) is:", "explanation": "Energy U = ½CV² = ½(ε₀A/d)(Ed)² = ½ε₀E² × (Ad). Volume between plates = Ad. So energy density u = U/(Ad) = ½ε₀E². This is a general result — the energy density of any electric field is ½ε₀E².", "correct_answer": "D", "concept_tags": ["energy-density", "electric-field-energy"], "payload": {"question_id": "cuet-phy-elec-capacitor-03", "subtopic": "Energy density", "topic_name": "Capacitance and Capacitors", "bloom_level": "remember", "options": [{"key": "A", "text": "ε₀E", "is_correct": false}, {"key": "B", "text": "ε₀E²", "is_correct": false}, {"key": "C", "text": "½ε₀²E²", "is_correct": false}, {"key": "D", "text": "½ε₀E²", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "ε₀E has dimensions of charge/area (surface charge density), not energy/volume.", "misconception": "Dimensional error"}, {"option_key": "B", "hint": "Missing the factor of ½. The correct expression is ½ε₀E², derived from integrating the work to build the field.", "misconception": "Forgetting the factor of ½ in energy density"}, {"option_key": "C", "hint": "½ε₀²E² has ε₀ squared, which gives wrong dimensions. Energy density requires exactly one power of ε₀.", "misconception": "Squaring ε₀ instead of E"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The capacitance of a cylindrical capacitor of length L with inner radius a and outer radius b is:", "explanation": "For a cylindrical capacitor, V = (λ/2πε₀)ln(b/a), where λ = Q/L. So C = Q/V = 2πε₀L/ln(b/a). This is analogous to the parallel plate formula but adapted for cylindrical geometry. The capacitance is proportional to length L.", "correct_answer": "A", "concept_tags": ["cylindrical-capacitor", "logarithmic-formula"], "payload": {"question_id": "cuet-phy-elec-capacitor-04", "subtopic": "Cylindrical capacitor", "topic_name": "Capacitance and Capacitors", "bloom_level": "remember", "options": [{"key": "A", "text": "2πε₀L/ln(b/a)", "is_correct": true}, {"key": "B", "text": "4πε₀L/ln(b/a)", "is_correct": false}, {"key": "C", "text": "2πε₀L/(b − a)", "is_correct": false}, {"key": "D", "text": "ε₀L/(b − a)", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "4πε₀ appears in the spherical capacitor formula, not the cylindrical one. The cylindrical geometry uses 2πε₀.", "misconception": "Confusing cylindrical with spherical geometry factor"}, {"option_key": "C", "hint": "The denominator should be ln(b/a), not (b − a). The logarithm arises from integrating E = λ/(2πε₀r) from a to b.", "misconception": "Using linear gap instead of logarithmic ratio"}, {"option_key": "D", "hint": "This lacks the 2π factor and uses (b−a) instead of ln(b/a). Both are incorrect for a cylindrical geometry.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The capacitance of a parallel plate capacitor is given by C = ε₀A/d. If the area of each plate is doubled, the capacitance:", "explanation": "Since C = ε₀A/d, the capacitance is directly proportional to the area A of the plates. If A is doubled, C also doubles. This is because a larger plate area can store more charge for the same potential difference.", "correct_answer": "B", "concept_tags": ["parallel plate capacitor", "capacitance formula", "plate area"], "payload": {"question_id": "cuet-phy-elec-capacitor-05", "subtopic": "Capacitors and Capacitance", "topic_name": "Capacitance and Capacitors", "bloom_level": "remember", "options": [{"key": "A", "text": "Remains the same", "is_correct": false}, {"key": "B", "text": "Becomes double", "is_correct": true}, {"key": "C", "text": "Becomes half", "is_correct": false}, {"key": "D", "text": "Becomes four times", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Capacitance depends on plate area, so changing the area will change the capacitance.", "misconception": "Thinking capacitance is independent of plate geometry"}, {"option_key": "C", "hint": "Capacitance is directly proportional to A, not inversely proportional. Doubling A increases C.", "misconception": "Confusing direct and inverse proportionality"}, {"option_key": "D", "hint": "Four times would occur if C ∝ A², but C is linearly proportional to A.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The SI unit of capacitance is:", "explanation": "The SI unit of capacitance is the farad (F), named after Michael Faraday. One farad is defined as the capacitance when one coulomb of charge produces a potential difference of one volt, i.e., 1 F = 1 C/V.", "correct_answer": "A", "concept_tags": ["capacitance", "SI unit", "farad"], "payload": {"question_id": "cuet-phy-elec-capacitor-06", "subtopic": "Capacitors and Capacitance", "topic_name": "Capacitance and Capacitors", "bloom_level": "remember", "options": [{"key": "A", "text": "Farad (F)", "is_correct": true}, {"key": "B", "text": "Coulomb (C)", "is_correct": false}, {"key": "C", "text": "Volt (V)", "is_correct": false}, {"key": "D", "text": "Henry (H)", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Coulomb is the unit of electric charge, not capacitance. Capacitance = charge/voltage.", "misconception": "Confusing charge with capacitance"}, {"option_key": "C", "hint": "Volt is the unit of electric potential or potential difference, not capacitance.", "misconception": null}, {"option_key": "D", "hint": "Henry is the unit of inductance (used in electromagnetic induction), not capacitance.", "misconception": "Confusing capacitance with inductance"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The capacitance of a parallel plate capacitor does NOT depend on:", "explanation": "The capacitance of a parallel plate capacitor is C = ε₀A/d (or C = κε₀A/d with a dielectric). It depends on plate area A, separation d, and the dielectric constant κ, but not on the charge stored on the plates or the potential difference applied.", "correct_answer": "D", "concept_tags": ["parallel plate capacitor", "capacitance factors", "charge independence"], "payload": {"question_id": "cuet-phy-elec-capacitor-07", "subtopic": "Capacitors and Capacitance", "topic_name": "Capacitance and Capacitors", "bloom_level": "remember", "options": [{"key": "A", "text": "Area of the plates", "is_correct": false}, {"key": "B", "text": "Distance between the plates", "is_correct": false}, {"key": "C", "text": "Nature of the dielectric medium", "is_correct": false}, {"key": "D", "text": "Charge on the plates", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "C = ε₀A/d clearly shows capacitance is directly proportional to plate area A.", "misconception": null}, {"option_key": "B", "hint": "C = ε₀A/d shows capacitance is inversely proportional to plate separation d.", "misconception": null}, {"option_key": "C", "hint": "When a dielectric is inserted, C = κε₀A/d, showing that the dielectric constant κ affects capacitance.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A parallel plate capacitor has capacitance C. If the distance between the plates is halved and a dielectric of constant K = 4 is filled in the entire space, the new capacitance is:", "explanation": "Original: C = ε₀A/d. New: d'' = d/2, K = 4. C'' = Kε₀A/d'' = 4ε₀A/(d/2) = 8ε₀A/d = 8C. Both changes (halving distance and inserting dielectric) independently multiply the capacitance.", "correct_answer": "D", "concept_tags": ["combined-effect", "dielectric-distance"], "payload": {"question_id": "cuet-phy-elec-capacitor-08", "subtopic": "Combined changes in capacitor", "topic_name": "Capacitance and Capacitors", "bloom_level": "apply", "options": [{"key": "A", "text": "2C", "is_correct": false}, {"key": "B", "text": "4C", "is_correct": false}, {"key": "C", "text": "6C", "is_correct": false}, {"key": "D", "text": "8C", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "2C accounts for halving the distance (×2) but ignores the dielectric (×4). Both effects multiply.", "misconception": "Considering only the distance change"}, {"option_key": "B", "hint": "4C accounts for the dielectric (×4) but ignores the halved distance (×2). The total factor is 4 × 2 = 8.", "misconception": "Considering only the dielectric effect"}, {"option_key": "C", "hint": "6C would come from adding 4 + 2 = 6, but the effects multiply (4 × 2 = 8), not add.", "misconception": "Adding individual factors instead of multiplying"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The force of attraction between the plates of a parallel plate capacitor charged to voltage V with plate area A and separation d is:", "explanation": "The electric field due to one plate is E₁ = σ/(2ε₀). Force on the other plate (charge Q = σA) is F = QE₁ = σA × σ/(2ε₀) = σ²A/(2ε₀). Using σ = ε₀V/d: F = ε₀V²A/(2d²). Alternatively, F = Q²/(2ε₀A) = ε₀AV²/(2d²).", "correct_answer": "C", "concept_tags": ["force-between-plates", "attractive-force"], "payload": {"question_id": "cuet-phy-elec-capacitor-09", "subtopic": "Force on capacitor plates", "topic_name": "Capacitance and Capacitors", "bloom_level": "apply", "options": [{"key": "A", "text": "ε₀AV²/d²", "is_correct": false}, {"key": "B", "text": "ε₀AV/d", "is_correct": false}, {"key": "C", "text": "ε₀AV²/(2d²)", "is_correct": true}, {"key": "D", "text": "ε₀AV²/(4d²)", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Missing the factor of ½. Each plate creates field σ/(2ε₀), not σ/ε₀ — only one plate''s field acts on the other.", "misconception": "Using the total field between plates instead of field due to one plate"}, {"option_key": "B", "hint": "This has V to the first power instead of V². Force depends on E² and E = V/d, so F ∝ V².", "misconception": "Using V instead of V²"}, {"option_key": "D", "hint": "The factor should be 1/2, not 1/4. F = σ²A/(2ε₀) = ε₀AV²/(2d²).", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A parallel plate capacitor is charged and disconnected from the battery. A dielectric slab of constant K is now inserted fully between the plates. Which of the following quantities increases?", "explanation": "With battery disconnected: Q = constant. Inserting dielectric: C → KC, V = Q/C → Q/(KC) = V/K (decreases), E = V/d → V/(Kd) (decreases), U = Q²/(2C) → Q²/(2KC) = U/K (decreases). Capacitance increases; V, E, and U all decrease.", "correct_answer": "A", "concept_tags": ["battery-disconnected", "dielectric-insertion", "quantity-changes"], "payload": {"question_id": "cuet-phy-elec-capacitor-10", "subtopic": "Dielectric with battery disconnected", "topic_name": "Capacitance and Capacitors", "bloom_level": "analyze", "options": [{"key": "A", "text": "Capacitance", "is_correct": true}, {"key": "B", "text": "Voltage across the plates", "is_correct": false}, {"key": "C", "text": "Electric field between the plates", "is_correct": false}, {"key": "D", "text": "Energy stored", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "V = Q/C. With Q constant and C increasing (×K), V must decrease to V/K.", "misconception": "Thinking voltage stays constant without the battery"}, {"option_key": "C", "hint": "E = V/d. Since V decreases (V/K) and d is unchanged, E also decreases. The dielectric polarization opposes the original field.", "misconception": "Ignoring field reduction by dielectric polarization"}, {"option_key": "D", "hint": "U = Q²/(2C). With Q constant and C increasing, U decreases. The energy goes into pulling the slab in (work done by the force of attraction).", "misconception": "Not tracking where the lost energy goes"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Two capacitors of capacitances C₁ and C₂ (C₁ > C₂) are charged to the same voltage V and then connected in parallel with like plates together. The common voltage after connection is:", "explanation": "Initial charges: Q₁ = C₁V, Q₂ = C₂V. Total charge = (C₁ + C₂)V. Total capacitance = C₁ + C₂. Common voltage V'' = (C₁ + C₂)V/(C₁ + C₂) = V. When both capacitors have the same initial voltage and are connected with like plates, no charge flows and the voltage remains V.", "correct_answer": "B", "concept_tags": ["charge-sharing", "same-voltage", "parallel-connection"], "payload": {"question_id": "cuet-phy-elec-capacitor-11", "subtopic": "Charge redistribution", "topic_name": "Capacitance and Capacitors", "bloom_level": "apply", "options": [{"key": "A", "text": "V/2", "is_correct": false}, {"key": "B", "text": "V", "is_correct": true}, {"key": "C", "text": "2V", "is_correct": false}, {"key": "D", "text": "C₁V/(C₁ + C₂)", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "V/2 would occur if only one capacitor were charged and the other uncharged, with equal capacitances. Here both are already at V.", "misconception": "Applying the unequal charge formula without checking initial conditions"}, {"option_key": "C", "hint": "The voltages don''t add. In parallel, the common voltage is total charge / total capacitance = V.", "misconception": "Adding voltages in parallel"}, {"option_key": "D", "hint": "This formula applies when only C₁ is charged to V and C₂ is uncharged. When both are at V, the answer simplifies to V.", "misconception": "Using the formula for one charged + one uncharged capacitor"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A dielectric slab of thickness t and dielectric constant K is placed between the plates of a parallel plate capacitor of plate separation d (t < d). The capacitance becomes:", "explanation": "The capacitor is split into two in series: air gap of (d − t) and dielectric of t. C = ε₀A / [d − t + t/K] = ε₀A / [d − t(1 − 1/K)]. This reduces to ε₀A/d when K = 1 and to ε₀A/(d − t) when K → ∞ (conductor).", "correct_answer": "D", "concept_tags": ["partial-dielectric", "series-combination", "effective-gap"], "payload": {"question_id": "cuet-phy-elec-capacitor-12", "subtopic": "Partial dielectric filling", "topic_name": "Capacitance and Capacitors", "bloom_level": "apply", "options": [{"key": "A", "text": "Kε₀A/d", "is_correct": false}, {"key": "B", "text": "ε₀A/(d − t)", "is_correct": false}, {"key": "C", "text": "Kε₀A/(d − t + Kt)", "is_correct": false}, {"key": "D", "text": "ε₀A/(d − t + t/K)", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "Kε₀A/d applies when the dielectric fills the entire gap. Here it fills only thickness t, leaving (d − t) as air.", "misconception": "Using the fully-filled formula for partially-filled capacitor"}, {"option_key": "B", "hint": "ε₀A/(d − t) would apply for a conducting slab (K → ∞). A dielectric with finite K doesn''t reduce the gap to (d − t).", "misconception": "Treating a dielectric slab as a conductor"}, {"option_key": "C", "hint": "Check the series formula: 1/C = (d−t)/(ε₀A) + t/(Kε₀A) = [d − t + t/K]/(ε₀A). The denominator is d − t + t/K, not d − t + Kt.", "misconception": "Multiplying by K instead of dividing by K for the dielectric region"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A parallel plate capacitor has a capacitance of 10 μF. If a dielectric of dielectric constant K = 4 is inserted between the plates completely, the new capacitance becomes:", "explanation": "When a dielectric of dielectric constant K is completely inserted between the plates, the new capacitance becomes C'' = KC. Here C = 10 μF and K = 4, so C'' = 4 × 10 = 40 μF. The dielectric increases capacitance by reducing the effective electric field between the plates.", "correct_answer": "D", "concept_tags": ["dielectric", "capacitance increase", "dielectric constant"], "payload": {"question_id": "cuet-phy-elec-capacitor-13", "subtopic": "Capacitors and Capacitance", "topic_name": "Capacitance and Capacitors", "bloom_level": "apply", "options": [{"key": "A", "text": "2.5 μF", "is_correct": false}, {"key": "B", "text": "10 μF", "is_correct": false}, {"key": "C", "text": "14 μF", "is_correct": false}, {"key": "D", "text": "40 μF", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "2.5 μF = 10/4, which would result from dividing by K instead of multiplying. Dielectric increases capacitance.", "misconception": "Dividing by dielectric constant instead of multiplying"}, {"option_key": "B", "hint": "10 μF is the original capacitance. Inserting a dielectric always increases the capacitance of a parallel plate capacitor.", "misconception": "Thinking dielectric does not change capacitance"}, {"option_key": "C", "hint": "14 μF = 10 + 4, which would result from adding K to C instead of multiplying.", "misconception": "Adding dielectric constant to capacitance"}]}}]'::jsonb, 'deploy-2026-03-05-b09');

SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A capacitor of capacitance 6 μF is charged to a potential of 100 V. The energy stored in the capacitor is:", "explanation": "The energy stored in a capacitor is U = ½CV². Here C = 6 μF = 6 × 10⁻⁶ F and V = 100 V. So U = ½ × 6 × 10⁻⁶ × (100)² = ½ × 6 × 10⁻⁶ × 10⁴ = ½ × 6 × 10⁻² = 0.03 J = 3 × 10⁻² J.", "correct_answer": "B", "concept_tags": ["energy stored", "capacitor", "numerical calculation"], "payload": {"question_id": "cuet-phy-elec-capacitor-14", "subtopic": "Capacitors and Capacitance", "topic_name": "Capacitance and Capacitors", "bloom_level": "apply", "options": [{"key": "A", "text": "6 × 10⁻² J", "is_correct": false}, {"key": "B", "text": "3 × 10⁻² J", "is_correct": true}, {"key": "C", "text": "3 × 10⁻⁴ J", "is_correct": false}, {"key": "D", "text": "6 × 10⁻⁴ J", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "6 × 10⁻² J results from forgetting the factor of ½ in the energy formula U = ½CV².", "misconception": "Forgetting the ½ factor in energy formula"}, {"option_key": "C", "hint": "3 × 10⁻⁴ J is 100 times too small, likely from using V = 10 V instead of V = 100 V or squaring incorrectly.", "misconception": "Error in squaring the voltage"}, {"option_key": "D", "hint": "6 × 10⁻⁴ J combines both errors: wrong power of ten and missing the ½ factor.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The capacitance of an isolated spherical conductor of radius R is:", "explanation": "For an isolated spherical conductor, the potential at its surface is V = kQ/R = Q/(4πε₀R). Since C = Q/V, we get C = Q/(Q/4πε₀R) = 4πε₀R. The capacitance of a spherical conductor depends linearly on its radius.", "correct_answer": "A", "concept_tags": ["spherical conductor", "capacitance", "isolated sphere"], "payload": {"question_id": "cuet-phy-elec-capacitor-15", "subtopic": "Capacitors and Capacitance", "topic_name": "Capacitance and Capacitors", "bloom_level": "understand", "options": [{"key": "A", "text": "4πε₀R", "is_correct": true}, {"key": "B", "text": "4πε₀R²", "is_correct": false}, {"key": "C", "text": "ε₀R", "is_correct": false}, {"key": "D", "text": "4πε₀/R", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "4πε₀R² has an extra factor of R. Capacitance is linearly proportional to the radius, not to R².", "misconception": "Confusing area dependence with radius dependence"}, {"option_key": "C", "hint": "ε₀R is missing the 4π factor that comes from the Coulomb constant k = 1/(4πε₀).", "misconception": null}, {"option_key": "D", "hint": "4πε₀/R would make capacitance decrease with increasing radius, which contradicts the physical expectation that larger conductors have greater capacitance.", "misconception": "Inverting the radius dependence"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A parallel plate capacitor with plate area A and separation d is charged to potential V. The electric field between the plates is E. If the separation is reduced to d/2 while the capacitor remains connected to the battery, the electric field becomes:", "explanation": "When the capacitor remains connected to the battery, the potential difference V across the plates stays constant. The electric field E = V/d. When separation becomes d/2, E'' = V/(d/2) = 2V/d = 2E. The electric field doubles.", "correct_answer": "C", "concept_tags": ["electric field", "parallel plate capacitor", "battery connected"], "payload": {"question_id": "cuet-phy-elec-capacitor-16", "subtopic": "Capacitors and Capacitance", "topic_name": "Capacitance and Capacitors", "bloom_level": "apply", "options": [{"key": "A", "text": "E/2", "is_correct": false}, {"key": "B", "text": "E", "is_correct": false}, {"key": "C", "text": "2E", "is_correct": true}, {"key": "D", "text": "4E", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "E/2 would be the result if the charge remained constant (battery disconnected) and separation was doubled, not halved.", "misconception": null}, {"option_key": "B", "hint": "The field does not remain E. With battery connected, V is constant, and since E = V/d, halving d doubles E.", "misconception": "Thinking electric field is independent of plate separation"}, {"option_key": "D", "hint": "4E would require the separation to be reduced to d/4, not d/2.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A parallel plate capacitor of capacitance C is connected to a battery of EMF V. A dielectric slab of constant K is inserted. The battery remains connected. The ratio of energy stored after to before insertion is:", "explanation": "With battery connected: V = constant. Before: U₁ = ½CV². After: C'' = KC, U₂ = ½KCV². Ratio = U₂/U₁ = K. The energy increases because the battery supplies additional charge (Q₂ = KCV > Q₁ = CV), doing work. Part of this work goes to increasing U and part to pulling in the dielectric.", "correct_answer": "C", "concept_tags": ["battery-connected", "energy-ratio", "dielectric"], "payload": {"question_id": "cuet-phy-elec-capacitor-17", "subtopic": "Dielectric with battery connected", "topic_name": "Capacitance and Capacitors", "bloom_level": "apply", "options": [{"key": "A", "text": "1/K", "is_correct": false}, {"key": "B", "text": "1/K²", "is_correct": false}, {"key": "C", "text": "K", "is_correct": true}, {"key": "D", "text": "K²", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "1/K is the energy ratio when the battery is disconnected (U = Q²/2C, Q constant, C increases). With battery connected, V is constant, so U = ½CV² increases by K.", "misconception": "Using the battery-disconnected result for battery-connected case"}, {"option_key": "B", "hint": "1/K² has no physical basis in this scenario. With V constant and C → KC: U → ½KCV² = KU.", "misconception": null}, {"option_key": "D", "hint": "K² would arise if both C and V changed, but with the battery connected, V stays constant. Only C changes by factor K.", "misconception": "Squaring K without justification"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A spherical capacitor has inner sphere of radius a and outer sphere of radius b. Its capacitance is:", "explanation": "The potential difference between spheres: V = kQ(1/a − 1/b) = kQ(b − a)/(ab). Capacitance C = Q/V = ab/(k(b − a)) = 4πε₀ab/(b − a). When b → ∞, C → 4πε₀a (isolated sphere). When (b − a) << a, it approximates a parallel plate capacitor.", "correct_answer": "A", "concept_tags": ["spherical-capacitor", "concentric-spheres"], "payload": {"question_id": "cuet-phy-elec-capacitor-18", "subtopic": "Spherical capacitor", "topic_name": "Capacitance and Capacitors", "bloom_level": "remember", "options": [{"key": "A", "text": "4πε₀ab/(b − a)", "is_correct": true}, {"key": "B", "text": "4πε₀(b − a)/ab", "is_correct": false}, {"key": "C", "text": "4πε₀a", "is_correct": false}, {"key": "D", "text": "4πε₀(a + b)", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "This inverts the fraction. C = Q/V = ab/[k(b−a)] = 4πε₀ab/(b−a), not (b−a)/ab.", "misconception": "Inverting the expression for capacitance"}, {"option_key": "C", "hint": "4πε₀a is the capacitance of an isolated sphere (outer radius → ∞). A spherical capacitor with finite b has a different formula.", "misconception": "Using isolated sphere formula for a spherical capacitor"}, {"option_key": "D", "hint": "4πε₀(a + b) doesn''t arise from the potential difference calculation. The correct formula has ab/(b − a).", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A parallel plate capacitor has two dielectric slabs of equal area A/2 each, placed side by side between the plates. Their dielectric constants are K₁ and K₂. The effective capacitance is:", "explanation": "Side-by-side placement means the two halves are in parallel. Each half has area A/2 and gap d. C₁ = K₁ε₀(A/2)/d, C₂ = K₂ε₀(A/2)/d. Total C = C₁ + C₂ = ε₀A(K₁ + K₂)/(2d). This is equivalent to using an effective K = (K₁ + K₂)/2.", "correct_answer": "B", "concept_tags": ["parallel-dielectrics", "side-by-side", "effective-capacitance"], "payload": {"question_id": "cuet-phy-elec-capacitor-19", "subtopic": "Multiple dielectrics", "topic_name": "Capacitance and Capacitors", "bloom_level": "apply", "options": [{"key": "A", "text": "ε₀A·K₁K₂/[d(K₁ + K₂)]", "is_correct": false}, {"key": "B", "text": "ε₀A(K₁ + K₂)/(2d)", "is_correct": true}, {"key": "C", "text": "2ε₀A(K₁ + K₂)/d", "is_correct": false}, {"key": "D", "text": "ε₀AK₁K₂/d", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This is the harmonic mean formula, which applies when dielectrics are stacked on top of each other (in series). Side-by-side gives the arithmetic mean.", "misconception": "Confusing series (stacked) with parallel (side-by-side) arrangement of dielectrics"}, {"option_key": "C", "hint": "The factor should be (K₁ + K₂)/2, not 2(K₁ + K₂). Each slab covers only half the area.", "misconception": "Using full area A for each half"}, {"option_key": "D", "hint": "K₁K₂ (product) is not the relevant operation. Side-by-side means parallel combination: add the individual capacitances.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "n identical capacitors, each of capacitance C, are first connected in series and then in parallel. The ratio of energy stored in the series combination to the parallel combination, when connected to the same battery of EMF V, is:", "explanation": "Series: C_s = C/n. U_s = ½(C/n)V². Parallel: C_p = nC. U_p = ½(nC)V². Ratio = U_s/U_p = (C/n)/(nC) = 1/n². The parallel combination stores n² times more energy because it has n² times the capacitance.", "correct_answer": "D", "concept_tags": ["series-parallel-energy", "ratio", "n-capacitors"], "payload": {"question_id": "cuet-phy-elec-capacitor-20", "subtopic": "Energy in combinations", "topic_name": "Capacitance and Capacitors", "bloom_level": "analyze", "options": [{"key": "A", "text": "1/n", "is_correct": false}, {"key": "B", "text": "n", "is_correct": false}, {"key": "C", "text": "n²", "is_correct": false}, {"key": "D", "text": "1/n²", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "1/n is the capacitance ratio C_s/C_p = (C/n)/(nC) = 1/n². The energy ratio equals the capacitance ratio (since V is the same), which is 1/n², not 1/n.", "misconception": "Computing n × (1/n) instead of (1/n) × (1/n)"}, {"option_key": "B", "hint": "n would mean the series combination stores more energy, but series has smaller capacitance and therefore less energy for the same V.", "misconception": "Inverting the ratio"}, {"option_key": "C", "hint": "n² is the ratio U_p/U_s, not U_s/U_p. The question asks series/parallel.", "misconception": "Computing the ratio in the wrong order"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "easy", "question_text": "The diagram shows a parallel plate capacitor connected to a battery. The electric field lines between the plates are drawn. The field between the plates is:", "explanation": "In a parallel plate capacitor, the electric field between the plates is uniform (constant magnitude and direction). The field lines are straight, parallel, and equally spaced, pointing from the positive plate to the negative plate. The magnitude is E = σ/ε₀ = V/d, where V is the voltage and d is the separation.", "correct_answer": "B", "concept_tags": ["parallel-plate-capacitor", "uniform-field", "field-lines"], "payload": {"question_id": "cuet-phy-elec-capacitor-21", "subtopic": "Parallel plate capacitor field", "topic_name": "Capacitance and Capacitors", "bloom_level": "remember", "options": [{"key": "A", "text": "Non-uniform, stronger near the plates", "is_correct": false}, {"key": "B", "text": "Uniform, directed from positive to negative plate", "is_correct": true}, {"key": "C", "text": "Zero between the plates", "is_correct": false}, {"key": "D", "text": "Radial, pointing outward from centre", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The field is uniform between infinite parallel plates. Non-uniformity only occurs near the edges (fringing effect), which is usually neglected.", "misconception": "Confusing edge effects with the bulk field"}, {"option_key": "C", "hint": "The field is zero outside the plates (fields cancel), not between them where both plates'' fields add up.", "misconception": "Confusing the region between plates with the region outside"}, {"option_key": "D", "hint": "A radial field occurs for spherical charge distributions. Parallel plates create a uniform (not radial) field.", "misconception": "Confusing parallel plate with spherical geometry"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "medium", "question_text": "The diagram shows three capacitors of capacitances C₁ = 2 μF, C₂ = 3 μF, and C₃ = 6 μF connected in parallel across a 12 V battery. The total charge stored in the combination is:", "explanation": "For parallel connection: C_total = C₁ + C₂ + C₃ = 2 + 3 + 6 = 11 μF. Total charge Q = C_total × V = 11 × 10⁻⁶ × 12 = 132 × 10⁻⁶ C = 132 μC. Each capacitor has the same voltage (12 V) but different charges.", "correct_answer": "D", "concept_tags": ["parallel-capacitors", "total-charge", "capacitance-addition"], "payload": {"question_id": "cuet-phy-elec-capacitor-22", "subtopic": "Capacitors in parallel", "topic_name": "Capacitance and Capacitors", "bloom_level": "apply", "options": [{"key": "A", "text": "24 μC", "is_correct": false}, {"key": "B", "text": "36 μC", "is_correct": false}, {"key": "C", "text": "72 μC", "is_correct": false}, {"key": "D", "text": "132 μC", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "24 μC = 2 × 12, which is the charge on C₁ alone. You need to add charges on all three capacitors.", "misconception": "Using only one capacitor''s charge"}, {"option_key": "B", "hint": "36 μC = 3 × 12, the charge on C₂ alone. In parallel, total Q = (C₁ + C₂ + C₃) × V.", "misconception": null}, {"option_key": "C", "hint": "72 μC = 6 × 12, the charge on C₃ alone. All three capacitors contribute to the total charge.", "misconception": "Using only the largest capacitor"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "medium", "question_text": "The diagram shows two capacitors C₁ = 4 μF and C₂ = 6 μF connected in series across a 20 V battery. The voltage across C₁ is:", "explanation": "For series connection: 1/C_eq = 1/C₁ + 1/C₂ = 1/4 + 1/6 = 5/12, so C_eq = 12/5 = 2.4 μF. Common charge Q = C_eq × V = 2.4 × 20 = 48 μC. Voltage across C₁: V₁ = Q/C₁ = 48/4 = 12 V. (Check: V₂ = 48/6 = 8 V, and 12 + 8 = 20 V ✓)", "correct_answer": "C", "concept_tags": ["series-capacitors", "voltage-division", "charge-conservation"], "payload": {"question_id": "cuet-phy-elec-capacitor-23", "subtopic": "Capacitors in series", "topic_name": "Capacitance and Capacitors", "bloom_level": "apply", "options": [{"key": "A", "text": "8 V", "is_correct": false}, {"key": "B", "text": "10 V", "is_correct": false}, {"key": "C", "text": "12 V", "is_correct": true}, {"key": "D", "text": "20 V", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "8 V is the voltage across C₂, not C₁. In series, the smaller capacitor gets the larger share of voltage (V ∝ 1/C).", "misconception": "Swapping the voltages across the two capacitors"}, {"option_key": "B", "hint": "10 V would mean equal splitting. But in series, voltage divides inversely with capacitance: V₁/V₂ = C₂/C₁ = 6/4 = 1.5, not 1.", "misconception": "Assuming equal voltage division in series"}, {"option_key": "D", "hint": "20 V is the total voltage. In series, the voltage is shared between capacitors, so each gets less than the total.", "misconception": "Thinking each capacitor gets the full battery voltage in series"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "hard", "question_text": "The figure shows a parallel plate capacitor with plate area A and separation d. A dielectric slab of thickness t (t < d) and dielectric constant K is inserted between the plates. The new capacitance is:", "explanation": "The system is equivalent to two capacitors in series: an air capacitor of gap (d − t) and a dielectric capacitor of gap t. C_air = ε₀A/(d − t), C_diel = Kε₀A/t. For series: 1/C = 1/C_air + 1/C_diel = (d − t)/(ε₀A) + t/(Kε₀A) = [K(d − t) + t]/(Kε₀A). So C = Kε₀A/[K(d − t) + t] = ε₀A/[d − t + t/K] = ε₀A/[d − t(1 − 1/K)].", "correct_answer": "A", "concept_tags": ["dielectric-slab", "partial-dielectric", "series-combination"], "payload": {"question_id": "cuet-phy-elec-capacitor-24", "subtopic": "Effect of dielectric on capacitance", "topic_name": "Capacitance and Capacitors", "bloom_level": "apply", "options": [{"key": "A", "text": "ε₀A / [d − t(1 − 1/K)]", "is_correct": true}, {"key": "B", "text": "Kε₀A/d", "is_correct": false}, {"key": "C", "text": "ε₀A/(d − t)", "is_correct": false}, {"key": "D", "text": "ε₀A/d", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Kε₀A/d assumes the dielectric fills the entire gap. Since t < d, the dielectric is partial and the formula must account for both air and dielectric regions.", "misconception": "Assuming the dielectric fills the complete gap"}, {"option_key": "C", "hint": "ε₀A/(d − t) would be correct if the dielectric had K → ∞ (a conductor). For a finite K, the dielectric region contributes t/K, not zero.", "misconception": "Treating the dielectric as a perfect conductor"}, {"option_key": "D", "hint": "ε₀A/d is the capacitance without any dielectric. Inserting a dielectric always increases the capacitance.", "misconception": "Ignoring the effect of the dielectric entirely"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): A parallel plate capacitor with a dielectric slab partially inserted is pulled inward — the dielectric slab experiences a force pulling it into the space between the plates.\nReason (R): The system tends to move toward a state of lower energy, and energy is lower with the dielectric fully inside when the battery is disconnected.", "explanation": "Both A and R are true, and R correctly explains A. When the battery is disconnected: Q is constant, and inserting the dielectric increases C, reducing U = Q²/(2C). The system seeks minimum energy, so the slab is pulled in. (When the battery is connected, U increases, but the battery does extra work — the slab is still pulled in.)", "correct_answer": "A", "concept_tags": ["dielectric-force", "energy-minimization", "slab-insertion"], "payload": {"question_id": "cuet-phy-elec-capacitor-25", "subtopic": "Force on dielectric slab", "topic_name": "Capacitance and Capacitors", "bloom_level": "analyze", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "R directly explains A — the energy minimization principle is precisely why the force acts to pull the slab in.", "misconception": "Not seeing the causal connection between energy minimization and the force"}, {"option_key": "C", "hint": "R is correct — with battery disconnected, U = Q²/(2C). As C increases (dielectric inserted), U decreases, confirming the system moves to lower energy.", "misconception": null}, {"option_key": "D", "hint": "A is correct — this is experimentally observed. A dielectric slab is always pulled into the capacitor gap.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): The capacitance of a parallel plate capacitor increases when a dielectric slab is introduced between its plates.\nReason (R): The dielectric reduces the effective electric field between the plates, thereby reducing the potential difference for the same charge.", "explanation": "Both assertion and reason are correct, and R is the correct explanation of A. The dielectric gets polarized and creates an opposing field that reduces the net electric field between the plates. Since V = Ed, the potential difference decreases for the same charge. Since C = Q/V, a decreased V for the same Q means increased C.", "correct_answer": "A", "concept_tags": ["dielectric effect", "capacitance increase", "electric field reduction"], "payload": {"question_id": "cuet-phy-elec-capacitor-26", "subtopic": "Capacitors and Capacitance", "topic_name": "Capacitance and Capacitors", "bloom_level": "understand", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "R directly explains A. The reduction in electric field reduces V for the same Q, which by C = Q/V gives a higher capacitance.", "misconception": "Not seeing the causal chain: reduced E → reduced V → increased C"}, {"option_key": "C", "hint": "R is correct — the dielectric does reduce the effective electric field due to polarization of the dielectric material.", "misconception": null}, {"option_key": "D", "hint": "A is correct — it is a well-established fact that inserting a dielectric increases capacitance by a factor K.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "hard", "question_text": "Assertion (A): When two capacitors charged to different voltages are connected in parallel, the total energy after connection is less than the total energy before connection.\nReason (R): Energy is lost as heat in the connecting wires due to transient current flow during charge redistribution.", "explanation": "Both A and R are true, and R correctly explains A. If C₁ at V₁ and C₂ at V₂ are connected, charge flows until voltages equalize. The energy loss ΔU = C₁C₂(V₁ − V₂)²/[2(C₁ + C₂)] > 0 whenever V₁ ≠ V₂. This energy is dissipated as Joule heating in the wires, regardless of wire resistance (lower R means faster current but same total heat).", "correct_answer": "A", "concept_tags": ["energy-loss", "charge-redistribution", "joule-heating"], "payload": {"question_id": "cuet-phy-elec-capacitor-27", "subtopic": "Energy loss in redistribution", "topic_name": "Capacitance and Capacitors", "bloom_level": "analyze", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "R explains A directly — the energy deficit (ΔU > 0) is accounted for exactly by the heat generated in the connecting wires.", "misconception": "Thinking the energy loss and heat are unrelated"}, {"option_key": "C", "hint": "R is correct — transient currents always flow when capacitors at different voltages are connected, and I²R heating occurs in any real wire.", "misconception": null}, {"option_key": "D", "hint": "A is correct — ΔU = C₁C₂(V₁−V₂)²/2(C₁+C₂) is always positive for V₁ ≠ V₂, confirming energy loss.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "hard", "question_text": "Assertion (A): When a charged capacitor is disconnected from the battery and the plate separation is increased, the energy stored in the capacitor increases.\nReason (R): When the battery is disconnected, the charge on the capacitor plates remains constant.", "explanation": "Both A and R are correct, and R explains A. With battery disconnected, Q is constant (R is correct). Energy U = Q²/(2C). When plate separation increases, C = ε₀A/d decreases. Since Q is constant and C decreases, U = Q²/(2C) increases (A is correct). The constant charge (R) is the reason why increasing separation leads to increased energy.", "correct_answer": "A", "concept_tags": ["battery disconnected", "energy change", "plate separation"], "payload": {"question_id": "cuet-phy-elec-capacitor-28", "subtopic": "Capacitors and Capacitance", "topic_name": "Capacitance and Capacitors", "bloom_level": "evaluate", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The fact that Q is constant (R) is precisely what determines how energy changes. With Q constant, U = Q²/(2C), so reducing C increases U.", "misconception": "Not recognizing that constant charge is the key condition determining energy behavior"}, {"option_key": "C", "hint": "R is correct — when the battery is disconnected, there is no path for charge to flow, so Q stays constant.", "misconception": null}, {"option_key": "D", "hint": "A is correct — with Q constant and C decreasing, U = Q²/(2C) must increase. The extra energy comes from the work done in pulling the plates apart against electrostatic attraction.", "misconception": "Thinking energy decreases when plates are separated"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "medium", "question_text": "Match the following expressions (Column I) with the corresponding physical quantities (Column II):\n\nColumn I:\nA. C = Q/V\nB. U = ½CV²\nC. C = ε₀A/d\nD. C = 4πε₀R\n\nColumn II:\n1. Energy stored in a capacitor\n2. Capacitance of a parallel plate capacitor\n3. General definition of capacitance\n4. Capacitance of an isolated spherical conductor", "explanation": "C = Q/V is the general definition of capacitance (A→3). U = ½CV² is the energy stored in a capacitor (B→1). C = ε₀A/d is the capacitance of a parallel plate capacitor (C→2). C = 4πε₀R is the capacitance of an isolated spherical conductor (D→4).", "correct_answer": "B", "concept_tags": ["capacitance formulas", "matching", "definitions"], "payload": {"question_id": "cuet-phy-elec-capacitor-29", "subtopic": "Capacitors and Capacitance", "topic_name": "Capacitance and Capacitors", "bloom_level": "understand", "options": [{"key": "A", "text": "A-1, B-3, C-2, D-4", "is_correct": false}, {"key": "B", "text": "A-3, B-1, C-2, D-4", "is_correct": true}, {"key": "C", "text": "A-2, B-1, C-3, D-4", "is_correct": false}, {"key": "D", "text": "A-3, B-2, C-1, D-4", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "A-1 would match C = Q/V with energy, but C = Q/V is the definition of capacitance, not an energy expression.", "misconception": "Confusing definition of capacitance with energy formula"}, {"option_key": "C", "hint": "A-2 would match C = Q/V with parallel plate capacitor. While C = Q/V applies to all capacitors, ε₀A/d is specific to parallel plate geometry.", "misconception": null}, {"option_key": "D", "hint": "B-2 and C-1 are swapped. U = ½CV² is an energy expression (should match 1), not a parallel plate formula.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "hard", "question_text": "For a parallel plate capacitor charged to voltage V and then disconnected from the battery, match the changes in Column I with the effects in Column II when plate separation is doubled:\n\nColumn I:\nA. Capacitance\nB. Charge on plates\nC. Potential difference\nD. Energy stored\n\nColumn II:\n1. Doubles\n2. Remains constant\n3. Halves\n4. Doubles", "explanation": "When battery is disconnected and d is doubled: Capacitance C = ε₀A/d halves (A→3). Charge Q remains constant as no charge can flow (B→2). Potential difference V = Q/C doubles since C halves (C→1 or C→4, both say ''Doubles''). Energy U = Q²/(2C) doubles since C halves (D→1 or D→4). The correct matching is A-3, B-2, C-1, D-4.", "correct_answer": "D", "concept_tags": ["battery disconnected", "plate separation change", "capacitor properties"], "payload": {"question_id": "cuet-phy-elec-capacitor-30", "subtopic": "Capacitors and Capacitance", "topic_name": "Capacitance and Capacitors", "bloom_level": "analyze", "options": [{"key": "A", "text": "A-1, B-2, C-3, D-4", "is_correct": false}, {"key": "B", "text": "A-3, B-1, C-2, D-4", "is_correct": false}, {"key": "C", "text": "A-2, B-3, C-1, D-4", "is_correct": false}, {"key": "D", "text": "A-3, B-2, C-1, D-4", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "A-1 implies capacitance doubles when separation doubles, but C = ε₀A/d shows C is inversely proportional to d, so C halves.", "misconception": "Thinking capacitance increases with plate separation"}, {"option_key": "B", "hint": "B-1 implies charge doubles, but with the battery disconnected, there is no source of additional charge. Charge must remain constant.", "misconception": "Thinking charge changes without a battery connected"}, {"option_key": "C", "hint": "A-2 implies capacitance stays the same, but changing the plate separation directly changes the capacitance.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "In a parallel combination of capacitors, the voltage across each capacitor is the same.", "explanation": "TRUE. In a parallel combination, both plates of each capacitor are connected to the same two nodes (same two wires). Therefore, the potential difference across each capacitor equals the potential difference between the nodes — all capacitors have the same voltage.", "correct_answer": "A", "concept_tags": ["parallel-combination", "same-voltage"], "payload": {"question_id": "cuet-phy-elec-capacitor-31", "subtopic": "Parallel combination", "topic_name": "Capacitance and Capacitors", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "In parallel, both terminals of each capacitor connect to the same nodes. By definition, voltage between two nodes is unique — so all capacitors share the same voltage.", "misconception": "Confusing parallel (same voltage) with series (same charge)"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "The capacitance of a parallel plate capacitor increases when the distance between the plates is decreased.", "explanation": "This statement is TRUE. The capacitance of a parallel plate capacitor is C = ε₀A/d. Since C is inversely proportional to d (the plate separation), decreasing d increases C.", "correct_answer": "A", "concept_tags": ["parallel plate capacitor", "plate separation", "capacitance"], "payload": {"question_id": "cuet-phy-elec-capacitor-32", "subtopic": "Capacitors and Capacitance", "topic_name": "Capacitance and Capacitors", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Since C = ε₀A/d, capacitance is inversely proportional to d. Decreasing d increases C, so the statement is true.", "misconception": "Confusing direct and inverse proportionality in C = ε₀A/d"}, {"option_key": "C", "hint": "This option is not applicable for true/false questions.", "misconception": null}, {"option_key": "D", "hint": "This option is not applicable for true/false questions.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "The capacitance of a capacitor depends on the charge stored or the voltage applied across it.", "explanation": "FALSE. Capacitance C = ε₀A/d (for a parallel plate capacitor) depends only on the geometry (plate area, separation) and the medium (dielectric constant). It does NOT depend on Q or V. The ratio Q/V is always constant for a given capacitor.", "correct_answer": "B", "concept_tags": ["capacitance-independence", "geometry-dependent"], "payload": {"question_id": "cuet-phy-elec-capacitor-33", "subtopic": "Definition of capacitance", "topic_name": "Capacitance and Capacitors", "bloom_level": "understand", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Although C = Q/V, the capacitance is a constant for a given capacitor. Doubling Q doubles V, keeping C unchanged. Capacitance depends on geometry and medium, not on Q or V.", "misconception": "Confusing the definition C = Q/V with dependence on Q or V"}]}}]'::jsonb, 'deploy-2026-03-05-b09');

SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "The energy stored in a capacitor is directly proportional to the square of the charge and also directly proportional to the capacitance.", "explanation": "This statement is FALSE. While U = Q²/(2C) shows energy is proportional to Q², it also shows energy is inversely proportional to C (not directly proportional). Alternatively, U = ½CV² shows energy is proportional to C only when V is constant.", "correct_answer": "B", "concept_tags": ["energy stored", "capacitor", "proportionality"], "payload": {"question_id": "cuet-phy-elec-capacitor-34", "subtopic": "Capacitors and Capacitance", "topic_name": "Capacitance and Capacitors", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "U = Q²/(2C) shows that for a given charge, energy is inversely proportional to capacitance, not directly proportional.", "misconception": "Confusing the different forms of the energy formula without recognizing which variables are held constant"}, {"option_key": "C", "hint": "This option is not applicable for true/false questions.", "misconception": null}, {"option_key": "D", "hint": "This option is not applicable for true/false questions.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "fill-in-blanks", "difficulty": "medium", "question_text": "The energy lost when a capacitor of capacitance C charged to voltage V is connected to an identical uncharged capacitor is _____.", "explanation": "Initial energy: U₁ = ½CV². After connection: total charge = CV shared between 2C → common voltage = V/2. Final energy: U₂ = ½(2C)(V/2)² = CV²/4. Energy lost = U₁ − U₂ = CV²/2 − CV²/4 = CV²/4 = U₁/2. Exactly half the initial energy is lost as heat.", "correct_answer": "C", "concept_tags": ["energy-loss", "identical-capacitors", "half-energy"], "payload": {"question_id": "cuet-phy-elec-capacitor-35", "subtopic": "Energy loss in charge sharing", "topic_name": "Capacitance and Capacitors", "bloom_level": "apply", "options": [{"key": "A", "text": "Zero", "is_correct": false}, {"key": "B", "text": "CV²/2", "is_correct": false}, {"key": "C", "text": "CV²/4", "is_correct": true}, {"key": "D", "text": "CV²/8", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Zero energy loss would violate energy conservation — the voltages are different before connection (V and 0), so current flows and energy is dissipated.", "misconception": "Thinking no energy is lost in charge redistribution"}, {"option_key": "B", "hint": "CV²/2 is the total initial energy. Not all of it is lost — half remains in the two capacitors at V/2 each.", "misconception": "Thinking all the energy is lost"}, {"option_key": "D", "hint": "CV²/8 would be the final energy in one of the capacitors, not the total energy lost.", "misconception": "Confusing the energy of one capacitor with the total energy loss"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "fill-in-blanks", "difficulty": "medium", "question_text": "A parallel plate capacitor has plates of area 100 cm² separated by a distance of 1 mm. The capacitance of this capacitor is _____ pF. (Take ε₀ = 8.85 × 10⁻¹² F/m)", "explanation": "C = ε₀A/d = 8.85 × 10⁻¹² × 100 × 10⁻⁴ / (1 × 10⁻³) = 8.85 × 10⁻¹² × 10⁻² / 10⁻³ = 8.85 × 10⁻¹² × 10 = 8.85 × 10⁻¹¹ F = 88.5 × 10⁻¹² F = 88.5 pF.", "correct_answer": "C", "concept_tags": ["parallel plate capacitor", "numerical calculation", "capacitance"], "payload": {"question_id": "cuet-phy-elec-capacitor-36", "subtopic": "Capacitors and Capacitance", "topic_name": "Capacitance and Capacitors", "bloom_level": "apply", "options": [{"key": "A", "text": "8.85", "is_correct": false}, {"key": "B", "text": "885", "is_correct": false}, {"key": "C", "text": "88.5", "is_correct": true}, {"key": "D", "text": "0.885", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "8.85 pF would result from using A = 10 cm² or an incorrect unit conversion for the area.", "misconception": "Error in converting cm² to m²"}, {"option_key": "B", "hint": "885 pF is ten times too large, possibly from using d = 0.1 mm instead of 1 mm.", "misconception": null}, {"option_key": "D", "hint": "0.885 pF is 100 times too small, likely from a double error in unit conversion.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "scenario-based", "difficulty": "medium", "question_text": "A student connects a 10 μF capacitor to a 12 V battery and fully charges it. She then disconnects the battery and connects this charged capacitor to an identical uncharged 10 μF capacitor.\n\nThe final voltage across each capacitor and the total energy lost in the process are:", "explanation": "Initial charge Q = CV = 10 × 10⁻⁶ × 12 = 120 μC. After connecting to an identical uncharged capacitor, charge is shared equally. Common voltage V'' = Q/(C₁ + C₂) = 120/(10 + 10) = 6 V. Initial energy = ½ × 10 × 10⁻⁶ × 144 = 720 μJ. Final energy = ½ × 20 × 10⁻⁶ × 36 = 360 μJ. Energy lost = 720 − 360 = 360 μJ.", "correct_answer": "D", "concept_tags": ["charge sharing", "common potential", "energy loss"], "payload": {"question_id": "cuet-phy-elec-capacitor-37", "subtopic": "Capacitors and Capacitance", "topic_name": "Capacitance and Capacitors", "bloom_level": "apply", "options": [{"key": "A", "text": "12 V across each, no energy lost", "is_correct": false}, {"key": "B", "text": "6 V across each, 720 μJ lost", "is_correct": false}, {"key": "C", "text": "6 V across each, no energy lost", "is_correct": false}, {"key": "D", "text": "6 V across each, 360 μJ lost", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "The voltage cannot remain 12 V because charge is shared between two capacitors. By charge conservation, the common voltage must be lower.", "misconception": "Thinking voltage remains constant during charge sharing"}, {"option_key": "B", "hint": "720 μJ is the total initial energy. Not all of it is lost — 360 μJ remains stored in the two capacitors.", "misconception": "Thinking all energy is dissipated during charge redistribution"}, {"option_key": "C", "hint": "Energy cannot be fully conserved when charge flows between capacitors at different potentials. The energy difference is dissipated as heat.", "misconception": "Ignoring energy loss during charge redistribution"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "scenario-based", "difficulty": "hard", "question_text": "A network consists of three capacitors: C₁ = 2 μF, C₂ = 4 μF, and C₃ = 4 μF. C₁ and C₂ are in series, and their combination is in parallel with C₃. This network is connected to a 12 V battery. Calculate the total charge supplied by the battery and the voltage across C₁.", "explanation": "C₁ and C₂ in series: 1/C₁₂ = 1/2 + 1/4 = 3/4, so C₁₂ = 4/3 μF. C₁₂ in parallel with C₃: C_total = 4/3 + 4 = 16/3 μF. Total charge Q = C_total × V = (16/3) × 12 = 64 μC. For C₁₂ branch: Q₁₂ = C₁₂ × 12 = (4/3) × 12 = 16 μC. This is also Q₁ (series). Voltage across C₁: V₁ = Q₁/C₁ = 16/2 = 8 V.", "correct_answer": "B", "concept_tags": ["network", "series-parallel", "voltage-charge"], "payload": {"question_id": "cuet-phy-elec-capacitor-38", "subtopic": "Capacitor networks", "topic_name": "Capacitance and Capacitors", "bloom_level": "apply", "options": [{"key": "A", "text": "Q_total = 64 μC; V₁ = 4 V", "is_correct": false}, {"key": "B", "text": "Q_total = 64 μC; V₁ = 8 V", "is_correct": true}, {"key": "C", "text": "Q_total = 48 μC; V₁ = 8 V", "is_correct": false}, {"key": "D", "text": "Q_total = 48 μC; V₁ = 6 V", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Q_total is correct (64 μC), but V₁ = Q₁₂/C₁ = 16/2 = 8 V, not 4 V. The 4 V is V₂ = Q₁₂/C₂ = 16/4 = 4 V (across C₂, not C₁).", "misconception": "Confusing V₁ with V₂ in the series branch"}, {"option_key": "C", "hint": "48 μC would be from C_total = 4 μF (just C₃ alone). C₁₂ = 4/3 μF adds to C₃ in parallel, giving 16/3 μF.", "misconception": "Forgetting the series combination contribution to total capacitance"}, {"option_key": "D", "hint": "Both values are incorrect. Q_total = (16/3) × 12 = 64 μC, not 48, and V₁ = 8 V, not 6 V.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "logical-sequence", "difficulty": "medium", "question_text": "Arrange the following steps in the correct order for finding the equivalent capacitance of a complex capacitor network:\n\n1. Identify which capacitors are in series and which are in parallel\n2. Redraw the circuit showing simplified equivalent capacitors\n3. Check for Wheatstone bridge symmetry or balanced conditions\n4. Assign node labels and trace the current path from positive to negative terminal of the battery", "explanation": "The correct approach is: First assign nodes and trace the path (4) to understand the topology. Then check for special symmetries like Wheatstone bridge (3), which can simplify the network. Then identify series/parallel groups (1). Finally redraw with equivalents (2) and repeat if needed. Order: 4 → 3 → 1 → 2.", "correct_answer": "D", "concept_tags": ["network-analysis", "methodology", "systematic-approach"], "payload": {"question_id": "cuet-phy-elec-capacitor-39", "subtopic": "Network analysis method", "topic_name": "Capacitance and Capacitors", "bloom_level": "analyze", "options": [{"key": "A", "text": "1 → 2 → 3 → 4", "is_correct": false}, {"key": "B", "text": "1 → 3 → 4 → 2", "is_correct": false}, {"key": "C", "text": "4 → 1 → 3 → 2", "is_correct": false}, {"key": "D", "text": "4 → 3 → 1 → 2", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "You can''t identify series/parallel (step 1) without first labelling nodes (step 4). Node labelling must come first to understand the topology.", "misconception": "Jumping to series/parallel identification without understanding the circuit topology"}, {"option_key": "B", "hint": "Step 4 (node labelling) must come before step 1 (series/parallel identification), not after.", "misconception": "Incorrect ordering of node identification"}, {"option_key": "C", "hint": "After labelling nodes (4), check for symmetry (3) before identifying series/parallel (1). A Wheatstone bridge eliminates one capacitor, simplifying subsequent steps.", "misconception": "Not prioritizing symmetry check before brute-force identification"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "logical-sequence", "difficulty": "hard", "question_text": "Arrange the following steps in the correct order for calculating the energy stored in a charged capacitor from first principles:", "explanation": "Step 1: Start with a partially charged capacitor (charge q, voltage q/C). Step 2: Calculate the infinitesimal work to add charge dq against the existing voltage. Step 3: Integrate over the full charging process to get total energy. Step 4: Rewrite using Q = CV to get equivalent forms. This derivation shows why U = ½CV², not CV² — the voltage builds up gradually during charging.", "correct_answer": "C", "concept_tags": ["energy-derivation", "integration", "capacitor-energy"], "payload": {"question_id": "cuet-phy-elec-capacitor-40", "subtopic": "Energy stored in a capacitor", "topic_name": "Capacitance and Capacitors", "bloom_level": "apply", "options": [{"key": "A", "text": "2 → 1 → 3 → 4", "is_correct": false}, {"key": "B", "text": "1 → 3 → 2 → 4", "is_correct": false}, {"key": "C", "text": "1 → 2 → 3 → 4", "is_correct": true}, {"key": "D", "text": "4 → 1 → 2 → 3", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "You must first set up the scenario (step 1: define the state of partial charging) before calculating the work (step 2).", "misconception": "Calculating work before defining the system state"}, {"option_key": "B", "hint": "Integration (step 3) must come after setting up the differential expression (step 2). You can''t integrate before knowing what to integrate.", "misconception": "Integrating before defining the integrand"}, {"option_key": "D", "hint": "The final expressions (step 4) are the result, not the starting point. The derivation starts from first principles.", "misconception": "Starting with the answer instead of deriving it"}]}}]'::jsonb, 'deploy-2026-03-05-b09');

